// Generate recommendations from opportunities
const items = $input.all();
const opportunities = items.filter(i => i.json.opportunity_score).map(i => i.json);
const gaps = items.filter(i => i.json.gap_type).map(i => i.json);
const linkOpps = items.filter(i => i.json.domain_authority && i.json.source).map(i => i.json);

const recommendations = [];

// Ranking opportunity recommendations
opportunities.slice(0, 3).forEach(opp => {
  recommendations.push({
    insight_type: 'keyword_opportunity',
    category: 'rankings',
    title: `Optimize "${opp.keyword}" for Page 1`,
    summary: `Currently ranking #${opp.position}. With ${opp.search_volume || 'unknown'} monthly searches, improving to top 3 could drive significant traffic.`,
    priority: opp.position <= 10 ? 'high' : 'medium',
    recommended_actions: JSON.stringify([{
      action: `Review and optimize ${opp.ranking_url || 'target page'} for "${opp.keyword}"`,
      effort: 'medium',
      impact: 'high'
    }]),
    data_sources: ['striking_distance', 'daily_rankings']
  });
});

// Competitive gap recommendations
gaps.slice(0, 2).forEach(gap => {
  recommendations.push({
    insight_type: 'competitive_insight',
    category: 'competitors',
    title: `Content Gap: "${gap.keyword}"`,
    summary: `${gap.competitor_domain} ranks #${gap.competitor_position} for this keyword, but we don't have content targeting it.`,
    priority: gap.competitor_position <= 5 ? 'high' : 'medium',
    recommended_actions: JSON.stringify([{
      action: `Create content targeting "${gap.keyword}" to compete with ${gap.competitor_domain}`,
      effort: 'high',
      impact: 'high'
    }]),
    data_sources: ['competitive_gaps', 'competitor_rankings']
  });
});

// Link opportunity recommendations
linkOpps.slice(0, 2).forEach(link => {
  recommendations.push({
    insight_type: 'optimization_suggestion',
    category: 'backlinks',
    title: `Link Opportunity: ${link.domain}`,
    summary: `DA ${link.domain_authority} site links to competitors. Potential outreach target.`,
    priority: link.domain_authority >= 50 ? 'high' : 'medium',
    recommended_actions: JSON.stringify([{
      action: `Reach out to ${link.domain} for link building opportunity`,
      effort: 'medium',
      impact: 'medium'
    }]),
    data_sources: ['link_opportunities']
  });
});

return recommendations.length > 0 ? recommendations.map(r => ({ json: r })) : [{ json: { skip: true } }];
